// Promification des fonctions
function getUserPromise(userId) {
    return new Promise((resolve, reject) => {
        getUser(userId, (err, user) => {
            if (err) reject(err);
            else resolve(user);
        });
    });
}

function getOrdersPromise(user) {
    return new Promise((resolve, reject) => {
        getOrders(user, (err, orders) => {
            if (err) reject(err);
            else resolve(orders);
        });
    });
}

function processOrderPromise(order) {
    return new Promise((resolve, reject) => {
        processOrder(order, (err, result) => {
            if (err) reject(err);
            else resolve(result);
        });
    });
}

// Enchaînement avec then/catch
getUserPromise(1)
    .then(user => getOrdersPromise(user))
    .then(orders => processOrderPromise(orders[0]))
    .then(result => console.log(result))
    .catch(err => console.error(err));

// Exemple de promesse aléatoire
const aleaPromise = new Promise((resolve, reject) => {
    const success = Math.random() < 0.5;
    setTimeout(() => {
        if (success) resolve('Succès !');
        else reject(new Error('Échec aléatoire'));
    }, 500);
});

aleaPromise
    .then(result => console.log(result))
    .catch(err => console.error('Erreur attrapée :', err.message))
    .finally(() => console.log('Opération terminée (succès ou échec).'));

// Rôle : .catch() capture l'erreur et exécute du code en conséquence.
// .finally() est toujours exécuté, que la promesse soit résolue ou rejetée.

async function traiterCommande(userId) {
    try {
        const user = await getUserPromise(userId);
        const orders = await getOrdersPromise(user);
        const result = await processOrderPromise(orders[0]);
        console.log(result);
    } catch (err) {
        console.error('Erreur dans le traitement :', err);
    }
}

traiterCommande(1);

function tacheA() { return new Promise(resolve => setTimeout(() => resolve('A'), Math.random() * 1000 + 500)); }
function tacheB() { return new Promise(resolve => setTimeout(() => resolve('B'), Math.random() * 1000 + 500)); }
function tacheC() { return new Promise(resolve => setTimeout(() => resolve('C'), Math.random() * 1000 + 500)); }

async function executionSequentielle() {
    const debut = Date.now();
    const a = await tacheA();
    const b = await tacheB();
    const c = await tacheC();
    const fin = Date.now();
    console.log(`Séquentiel : ${fin - debut} ms`, a, b, c);
}

async function executionParallele() {
    const debut = Date.now();
    const [a, b, c] = await Promise.all([tacheA(), tacheB(), tacheC()]);
    const fin = Date.now();
    console.log(`Parallèle : ${fin - debut} ms`, a, b, c);
}

// Interprétation : l'exécution séquentielle cumule les durées de chaque tâche (environ somme des délais), tandis que l'exécution parallèle (Promise.all) attend la tâche la plus longue, réduisant ainsi le temps total.

// Simulateur d'API
function getCoords(ville) {
    return new Promise((resolve, reject) => {
        setTimeout(() => {
            if (ville.toLowerCase() === 'paris') resolve({ lat: 48.8566, lon: 2.3522 });
            else if (ville.toLowerCase() === 'yaoundé') resolve({ lat: 3.8480, lon: 11.5021 });
            else reject(new Error(`Ville "${ville}" inconnue`));
        }, 500);
    });
}

function getCurrentWeather(lat, lon) {
    return new Promise((resolve) => {
        setTimeout(() => resolve(`Météo actuelle à (${lat},${lon}) : 22°C, ensoleillé`), 600);
    });
}

function getForecast(lat, lon) {
    return new Promise((resolve, reject) => {
        setTimeout(() => {
            if (Math.random() > 0.2) resolve(`Prévisions : 3 jours de beau temps`);
            else reject(new Error('Erreur réseau pour les prévisions'));
        }, 700);
    });
}

async function afficherMeteo(ville) {
    try {
        const coords = await getCoords(ville);
        const [meteo, previsions] = await Promise.all([
            getCurrentWeather(coords.lat, coords.lon),
            getForecast(coords.lat, coords.lon)
        ]);
        console.log({ ville, meteoActuelle: meteo, previsions });
    } catch (erreur) {
        console.error(`Impossible d'afficher la météo : ${erreur.message}`);
    }
}

